steps:
destruct c; unfold compare;
  rewrite ?compare_Eq, ?compare_Lt, ?compare_Gt;
  transitivity y; auto.

destruct o, o'; simpl;
rewrite ?P.le_lteq; intuition auto;
subst_eqns; pose proof (StrictOrder_Transitive x y z); eauto with *.

destruct c; unfold compare;
 do 2 (destruct O.compare; intros; try discriminate);
 elim_comp; auto.

induction x; intros [y|y|] [|l o r]; simpl remove; rewrite ?mem_node;
     simpl mem; try (rewrite IHx; clear IHx); rewrite ?mem_Leaf;
     intuition congruence.

induction x; destruct s; destruct s' as [|l' o' r']; simpl diff;
     rewrite ?mem_node; simpl mem;
      try (rewrite IHx; clear IHx); try intuition congruence.

destruct e1, e2; simpl; try reflexivity; try (case ceqb_spec);
try intro H; try rewrite H; simpl;
try apply eq_refl; try (ring [phi_0]).

destruct e1, e2; simpl; try reflexivity; try case ceqb_spec;
 try intro H; try rewrite H; simpl;
 try rewrite phi_0; try reflexivity;
 try (symmetry; apply rsub_0_l); try (symmetry; apply rsub_0_r).

induction n as [|n IHn]; simpl; intros P1;
 generalize (POneSubst_ok P1 cM1 P2); destruct POneSubst;
   intros; rewrite <- ?IHn; auto; reflexivity.

induction m as [|m IHm]; simpl; intros LM1 P2 H;
 assert (H' := PSubstL_ok n LM1 P2); destruct PSubstL;
 auto; try reflexivity.

induction p as [p IHp|p IHp|];simpl;intros;
    rewrite ?subst_l_ok, ?Pmul_ok, ?IHp;
    mul_permut.

intros x y l; induction l;
        [ simpl; auto
          | simpl; destruct 1 as [H1| ];
            [ left; rewrite H1; trivial | right; auto ] ].

intro l; induction l;
      [ simpl; tauto
        | simpl; intros l' x y H H0; apply in_or_app; destruct H as [H|H];
          [ left; rewrite H; apply in_prod_aux; assumption | right; auto ] ].

intros x; induction x as [x IH | x IH |]; simpl;
try apply (Rplus_pos_pos sor); try apply (Rtimes_pos_pos sor); try apply (Rplus_pos_pos sor);
try apply (Rlt_0_1 sor); assumption.

destruct (or_is_X (abst_form (negb pol) f1) (abst_form false f2) &&
                          or_is_X (abst_form pol f1) (abst_form true f2)
                 ) ; auto.

intros T U fct env k f;
      induction f as [| | | |? ? IHf1 ? IHf2|? ? IHf1 ? IHf2|? ? IHf
        |? ? IHf1 ? ? IHf2|? ? IHf1 ? IHf2|? IHf1 ? IHf2];
      simpl ; try (rewrite IHf1 ; rewrite IHf2) ; auto.

induction p ; simpl;auto;
    rewrite <- IHp;
    repeat rewrite Q2R_mult;
    reflexivity.

destruct o1; simpl;
  rewrite (Pmul_ok (SORsetoid sor) Rops_wd
    (Rth_ARth (SORsetoid sor) Rops_wd (SORrt sor))  (SORrm addon));
  apply OpMult_sound with (3:= H);assumption.

destruct o1; simpl;
  rewrite (Padd_ok (SORsetoid sor) Rops_wd
    (Rth_ARth (SORsetoid sor) Rops_wd (SORrt sor))  (SORrm addon));
  apply OpAdd_sound with (3:= H);assumption.

induction n as [|n IHn]; simpl; intros P1;
 generalize (POneSubst_ok P1 M1 P2); destruct POneSubst;
   intros; rewrite <- ?IHn; auto; reflexivity.

induction m as [|m IHm]; simpl; intros LM1 P2 **;
 assert (H' := PSubstL_ok n LM1 P2); destruct PSubstL;
 auto; try reflexivity.

now case h; [now simpl|..];
    simpl;intro H; exfalso; revert H; apply Nat.le_ngt;
    rewrite List.length_app; apply Nat.le_add_l.

now case d; intro d'; simpl;
    rewrite <-(of_list_to_list (app _ _)), app_spec;
    rewrite List.app_nil_r, of_list_to_list.

induction d; intros d' H; simpl in *;
  try destruct (nztail d) eqn:E;
  (rewrite IHd;[reflexivity|discriminate]) || (now rewrite ?nzhead_revapp_0).

now case nztail;
    [intros _ H _ H'; rewrite (H eq_refl), (H' eq_refl)
    |intros d'' H _ H' _; rewrite H; [rewrite H'|]..].

induction d; simpl; intro d'; [ now rewrite N.mul_1_r | .. ];
  unfold rev; simpl revapp; rewrite 2 IHd;
  rewrite <- N.add_assoc; f_equal; simpl_of_lu; simpl of_lu;
  rewrite N.pow_succ_r'; ring.

induction d; intros; simpl usize;
  [ simpl; now rewrite Pos.mul_1_r | .. ];
  rewrite N.pow_succ_r';
  unfold rev; simpl revapp; try rewrite of_lu_revapp; simpl of_lu;
  rewrite of_uint_acc_eqn by easy; simpl tl; simpl hd;
  rewrite IHd, Nadd_simpl; ring.

induction d; try destruct IHd as (IH1,IH2);
  simpl Little.double; simpl Little.succ_double;
  repeat (simpl_of_lu; rewrite ?IH1, ?IH2); split; reflexivity || ring.

induction d; [reflexivity|..];
  simpl_of_lu; rewrite Nadd_alt; simpl_to_nat;
  rewrite ?nat_iter_S, nat_iter_0, ?to_lu_succ, to_of_lu_tenfold by assumption;
  unfold lnorm; simpl; destruct nztail; auto.

induction d; simpl; intro d'; [ now rewrite N.mul_1_r | .. ];
  unfold rev; simpl revapp; rewrite 2 IHd;
  rewrite <- N.add_assoc; f_equal; simpl_of_lu; simpl of_lu;
  rewrite N.pow_succ_r'; ring.

induction d; intros; simpl usize;
  [ simpl; now rewrite Pos.mul_1_r | .. ];
  rewrite N.pow_succ_r';
  unfold rev; simpl revapp; try rewrite of_lu_revapp; simpl of_lu;
  rewrite of_uint_acc_eqn by easy; simpl tl; simpl hd;
  rewrite IHd, Nadd_simpl; ring.

induction d; try destruct IHd as (IH1,IH2);
  simpl Little.double; simpl Little.succ_double;
  repeat (simpl_of_lu; rewrite ?IH1, ?IH2); split; reflexivity || ring.

induction d; [reflexivity|..];
  simpl_of_lu; rewrite Nadd_alt; simpl_to_nat;
  rewrite ?nat_iter_S, nat_iter_0, ?to_lu_succ, to_of_lu_tenfold by assumption;
  unfold lnorm; simpl nztail; destruct nztail; reflexivity.

now case h; [now simpl|..];
    simpl;intro H; exfalso; revert H; apply Nat.le_ngt;
    rewrite List.length_app; apply Nat.le_add_l.

now case d; intro d'; simpl;
    rewrite <-(of_list_to_list (app _ _)), app_spec;
    rewrite List.app_nil_r, of_list_to_list.

induction d; intros d' H; simpl in *;
  try destruct (nztail d) eqn:E;
  (rewrite IHd;[reflexivity|discriminate]) || (now rewrite ?nzhead_revapp_0).

now case nztail;
    [intros _ H _ H'; rewrite (H eq_refl), (H' eq_refl)
    |intros d'' H _ H' _; rewrite H; [rewrite H'|]..].

induction d; intro d'; simpl usize;
  [ simpl; now rewrite Nat.mul_1_r | .. ];
  unfold rev; simpl revapp; rewrite 2 IHd;
  rewrite <- Nat.add_assoc; f_equal; simpl_of_lu; simpl of_lu;
  rewrite Nat.pow_succ_r'; ring.

induction d; intros;
  simpl Nat.of_uint_acc; rewrite ?Nat.tail_mul_spec, ?IHd;
  simpl rev; simpl usize; rewrite ?Nat.pow_succ_r';
  [ simpl; now rewrite Nat.mul_1_r | .. ];
  unfold rev at 2; simpl revapp; rewrite of_lu_revapp;
  simpl of_lu; ring.

induction d; [ reflexivity | .. ];
    simpl_of_lu;
    rewrite ?Nat.add_succ_l, Nat.add_0_l, ?to_lu_succ, to_of_lu_tenfold
      by assumption;
    unfold lnorm; simpl; now destruct nztail.

induction d; intro d'; simpl usize;
  [ simpl; now rewrite Nat.mul_1_r | .. ];
  unfold rev; simpl revapp; rewrite 2 IHd;
  rewrite <- Nat.add_assoc; f_equal; simpl_of_lu; simpl of_lu;
  rewrite Nat.pow_succ_r'; ring.

induction d; intros;
  simpl Nat.of_hex_uint_acc; rewrite ?Nat.tail_mul_spec, ?IHd;
  simpl rev; simpl usize; rewrite ?Nat.pow_succ_r';
  [ simpl; now rewrite Nat.mul_1_r | .. ];
  unfold rev at 2; simpl revapp; rewrite of_lu_revapp;
  simpl of_lu; ring.

induction d; [ reflexivity | .. ];
  simpl_of_lu;
  rewrite ?Nat.add_succ_l, Nat.add_0_l, ?to_lu_succ, to_of_lu_sixteenfold
   by assumption;
  unfold lnorm; cbn; now destruct nztail.

intros n m; split; intro;
[apply square_lt_mono_nonneg | apply square_lt_simpl_nonneg];
try assumption; apply le_0_l.

intros n m; split; intro;
[apply square_le_mono_nonneg | apply square_le_simpl_nonneg];
try assumption; apply le_0_l.

intros l x e r; induction elt, l, x, e, r, (bal l x e r) using bal_ind; intros; clearf;
 inv avl; simpl in *;
 match goal with |- avl (assert_false _ _ _ _) => avl_nns
  | _ => repeat apply create_avl; simpl in *; auto
 end; omega_max.

intros m1 m2; induction elt, elt', elt'', f, mapl, mapr, m1, m2, (map2_opt m1 m2) using map2_opt_ind; clearf; auto;
factornode _x0 _x1 _x2 _x3 _x4 as r2; intros;
destruct (split_avl x1 H0); rewrite H1 in *; simpl in *; inv avl;
auto using join_avl, concat_avl.

induction i; intros; destruct j; simpl;
 try rewrite (IHi (xI j));
 try rewrite (IHi (xO j));
 try rewrite <- (IHi xH);
 auto.

induction i; intros; destruct j; simpl;
 try rewrite (IHi (xI j));
 try rewrite (IHi (xO j));
 try rewrite <- (IHi xH);
 auto.

intros (m,Hm); induction m;
 intros (m', Hm'); destruct m'; unfold eq; simpl;
 try destruct a as (x,e); try destruct p as (x',e'); auto.

induction x; intros [y|y|] [|l o r]; simpl remove; rewrite ?mem_node;
     simpl mem; try (rewrite IHx; clear IHx); rewrite ?mem_Leaf;
     intuition congruence.

induction x; destruct s; destruct s' as [|l' o' r']; simpl diff;
     rewrite ?mem_node; simpl mem;
      try (rewrite IHx; clear IHx); try intuition congruence.

intros m x; induction elt, x, m, (find x m) using find_ind; auto; intros; clearf;
  inv bst; intuition_in; simpl; auto;
 try solve [order | absurd (X.lt x y); eauto with ordered_type | absurd (X.lt y x); eauto with ordered_type].

intros l x e r; induction elt, l, x, e, r, (bal l x e r) using bal_ind; subst; intros; clearf;
 inv bst; repeat apply create_bst; auto; unfold create; try constructor;
 (apply lt_tree_node || apply gt_tree_node); auto with ordered_type;
 (eapply lt_tree_trans || eapply gt_tree_trans); eauto with ordered_type.

destruct (X.compare x k);
 intros; inv bst; try rewrite bal_mapsto; unfold create; auto;
   inv MapsTo; auto; order.

destruct (X.compare x k);
   intros; inv bst; try rewrite bal_mapsto; unfold create; auto;
   try solve [inv MapsTo; auto].

intros m x; induction elt, x, m, (split x m) using split_ind; clearf; subst; simpl; auto;
  intros; inv bst; try clear e0;
  destruct X.compare; try order; trivial; rewrite <- IHt, H1; auto.

intros x y H; case (Zlt_cotrans (x + y) 0 H x); intro Hxy;
    [ right; apply (Z.add_lt_mono_l _ _ x); rewrite Z.add_0_r | left ];
    assumption.

intros a b; destruct a as [ |a|a]; destruct b as [ |b|b]; simpl; auto with zarith;
  generalize (Z.div_pos (Zpos a) (Zpos b)); unfold Z.div, Z.div_eucl;
  destruct Z.pos_div_eucl as (q,r); destruct r;
  rewrite ?Z.mul_1_r, <-?Z.opp_eq_mul_m1, ?Z.sgn_opp, ?Z.opp_involutive;
  match goal with [|- (_ -> _ -> ?P) -> _] =>
     intros HH; assert (HH1 : P); auto using Pos2Z.is_pos, Pos2Z.is_nonneg
  end; apply Z.sgn_nonneg; auto using Z.add_nonneg_nonneg, Z.le_succ_diag_r.

destruct z as [|p|p]; simpl; trivial;
  destruct (Pos2Nat.is_succ p) as (n,H); rewrite H; simpl; f_equal;
   now apply SuccNat2Pos.inv.

induction p as [p IHp|p IHp|]; intros q; destruct q; simpl; trivial;
 rewrite ?Pos.compare_xI_xI, ?Pos.compare_xO_xI,
  ?Pos.compare_xI_xO, ?Pos.compare_xO_xO, IHp; simpl;
 case Pos.compare_spec; intros; simpl; trivial;
  (now rewrite Pos.sub_xI_xI) || (now rewrite Pos.sub_xO_xO) ||
  (now rewrite Pos.sub_xO_xI) || (now rewrite Pos.sub_xI_xO) ||
  subst; unfold Pos.sub; simpl; now rewrite Pos.sub_mask_diag.

destruct n as [|n|n], m as [|m|m]; simpl; trivial;
 rewrite <- ? Pos.compare_antisym, ?pos_sub_spec;
 case Pos.compare_spec; trivial.

destruct a as [|a|a], b as [|b|b]; simpl; trivial;
 generalize (N.pos_div_eucl_spec a (N.pos b)); case N.pos_div_eucl; trivial;
  intros q r;
  try change (neg a) with (-pos a);
  change (pos a) with (of_N (N.pos a)); intros ->; now destruct q, r.

destruct a as [ |p|p], b as [ |q|q]; simpl; auto;
  generalize (Pos.ggcd_gcd p q); destruct Pos.ggcd as (g,(aa,bb));
  simpl; congruence.

destruct a as [ |p|p], b as [ |q|q]; simpl; rewrite ?Pos.mul_1_r; auto;
  generalize (Pos.ggcd_correct_divisors p q);
  destruct Pos.ggcd as (g,(aa,bb)); simpl; destruct 1; now subst.

apply meq_trans with
    (munion (singletonBag a) (munion (list_contents l0) (list_contents m)));
    auto with datatypes.

intros;
  replace (a :: l) with ([] ++ a :: l); trivial;
    apply permut_add_inside_eq; trivial.

intros;
    replace (a :: l) with ([] ++ a :: l); trivial;
        apply permut_add_inside; trivial.

intros l1 l2;
    unfold permutation, meq;
        intro a; do 2 rewrite list_contents_app; simpl;
          auto with arith.

intros x y H; case (Rtotal_order x y); [ intros H1 | intros [H1| H1] ]; auto;
    assert (H2 := exp_increasing _ _ H1); rewrite H in H2;
      elim (Rlt_irrefl _ H2).

rewrite sqrt_pow2;
 [|apply Rlt_le, Rmult_lt_0_compat;[apply Rplus_lt_0_compat; apply exp_pos |
                            apply Rinv_0_lt_compat, Rlt_0_2]].

intros; generalize (Rge_le (frac_part r1 + frac_part r2) 1 H); intro; clear H;
    elim (base_fp r1); elim (base_fp r2); intros; clear H H2;
    generalize (Rplus_lt_compat_l (frac_part r2) (frac_part r1) 1 H3);
    intro; clear H3; generalize (Rplus_lt_compat_l 1 (frac_part r2) 1 H1);
    intro; clear H1; rewrite (Rplus_comm 1 (frac_part r2)) in H2;
    generalize
      (Rlt_trans (frac_part r2 + frac_part r1) (frac_part r2 + 1) 2 H H2);
    intro; clear H H2; rewrite (Rplus_comm (frac_part r2) (frac_part r1)) in H1;
    unfold frac_part in H0, H1; unfold Rminus in H0, H1;
    rewrite (Rplus_assoc r1 (- IZR (Int_part r1)) (r2 + - IZR (Int_part r2)))
    in H1; rewrite (Rplus_comm r2 (- IZR (Int_part r2))) in H1;
    rewrite <- (Rplus_assoc (- IZR (Int_part r1)) (- IZR (Int_part r2)) r2)
    in H1;
    rewrite (Rplus_comm (- IZR (Int_part r1) + - IZR (Int_part r2)) r2) in H1;
    rewrite <- (Rplus_assoc r1 r2 (- IZR (Int_part r1) + - IZR (Int_part r2)))
    in H1;
    rewrite <- (Ropp_plus_distr (IZR (Int_part r1)) (IZR (Int_part r2))) in H1;
    rewrite (Rplus_assoc r1 (- IZR (Int_part r1)) (r2 + - IZR (Int_part r2)))
    in H0; rewrite (Rplus_comm r2 (- IZR (Int_part r2))) in H0;
    rewrite <- (Rplus_assoc (- IZR (Int_part r1)) (- IZR (Int_part r2)) r2)
    in H0;
    rewrite (Rplus_comm (- IZR (Int_part r1) + - IZR (Int_part r2)) r2) in H0;
    rewrite <- (Rplus_assoc r1 r2 (- IZR (Int_part r1) + - IZR (Int_part r2)))
    in H0;
    rewrite <- (Ropp_plus_distr (IZR (Int_part r1)) (IZR (Int_part r2))) in H0;
    generalize
      (Rplus_le_compat_l (IZR (Int_part r1) + IZR (Int_part r2)) 1
                         (r1 + r2 + - (IZR (Int_part r1) + IZR (Int_part r2))) H0);
    intro; clear H0;
    generalize
      (Rplus_lt_compat_l (IZR (Int_part r1) + IZR (Int_part r2))
                         (r1 + r2 + - (IZR (Int_part r1) + IZR (Int_part r2))) 2 H1);
    intro; clear H1;
    rewrite (Rplus_comm (r1 + r2) (- (IZR (Int_part r1) + IZR (Int_part r2))))
    in H;
    rewrite <-
            (Rplus_assoc (IZR (Int_part r1) + IZR (Int_part r2))
                         (- (IZR (Int_part r1) + IZR (Int_part r2))) (r1 + r2))
    in H; rewrite (Rplus_opp_r (IZR (Int_part r1) + IZR (Int_part r2))) in H;
    elim (Rplus_ne (r1 + r2)); intros a b; rewrite b in H;
    clear a b;
    rewrite (Rplus_comm (r1 + r2) (- (IZR (Int_part r1) + IZR (Int_part r2))))
    in H0;
    rewrite <-
            (Rplus_assoc (IZR (Int_part r1) + IZR (Int_part r2))
                         (- (IZR (Int_part r1) + IZR (Int_part r2))) (r1 + r2))
    in H0; rewrite (Rplus_opp_r (IZR (Int_part r1) + IZR (Int_part r2))) in H0;
    elim (Rplus_ne (r1 + r2)); intros a b; rewrite b in H0;
    clear a b;
    change 2 with (1 + 1) in H0;
    rewrite <- (Rplus_assoc (IZR (Int_part r1) + IZR (Int_part r2)) 1 1) in H0;
    auto with real.

rewrite <- (plus_IZR (Int_part r1) (Int_part r2)) in H;
    rewrite <- (plus_IZR (Int_part r1) (Int_part r2)) in H0;
    rewrite <- (plus_IZR (Int_part r1 + Int_part r2) 1) in H;
    rewrite <- (plus_IZR (Int_part r1 + Int_part r2) 1) in H0;
    rewrite <- (plus_IZR (Int_part r1 + Int_part r2 + 1) 1) in H0;
    generalize (up_tech (r1 + r2) (Int_part r1 + Int_part r2 + 1) H H0);
    intro; clear H H0; unfold Int_part at 1.

intros; elim (base_fp r1); elim (base_fp r2); intros; clear H1 H3;
    generalize (Rge_le (frac_part r2) 0 H0); intro; clear H0;
    generalize (Rge_le (frac_part r1) 0 H2); intro; clear H2;
    generalize (Rplus_le_compat_l (frac_part r1) 0 (frac_part r2) H1);
    intro; clear H1; elim (Rplus_ne (frac_part r1)); intros a b;
    rewrite a in H2; clear a b;
    generalize (Rle_trans 0 (frac_part r1) (frac_part r1 + frac_part r2) H0 H2);
    intro; clear H0 H2; unfold frac_part in H, H1; unfold Rminus in H, H1;
    rewrite (Rplus_assoc r1 (- IZR (Int_part r1)) (r2 + - IZR (Int_part r2)))
    in H1; rewrite (Rplus_comm r2 (- IZR (Int_part r2))) in H1;
    rewrite <- (Rplus_assoc (- IZR (Int_part r1)) (- IZR (Int_part r2)) r2)
    in H1;
    rewrite (Rplus_comm (- IZR (Int_part r1) + - IZR (Int_part r2)) r2) in H1;
    rewrite <- (Rplus_assoc r1 r2 (- IZR (Int_part r1) + - IZR (Int_part r2)))
    in H1;
    rewrite <- (Ropp_plus_distr (IZR (Int_part r1)) (IZR (Int_part r2))) in H1;
    rewrite (Rplus_assoc r1 (- IZR (Int_part r1)) (r2 + - IZR (Int_part r2)))
    in H; rewrite (Rplus_comm r2 (- IZR (Int_part r2))) in H;
    rewrite <- (Rplus_assoc (- IZR (Int_part r1)) (- IZR (Int_part r2)) r2) in H;
    rewrite (Rplus_comm (- IZR (Int_part r1) + - IZR (Int_part r2)) r2) in H;
    rewrite <- (Rplus_assoc r1 r2 (- IZR (Int_part r1) + - IZR (Int_part r2)))
    in H;
    rewrite <- (Ropp_plus_distr (IZR (Int_part r1)) (IZR (Int_part r2))) in H;
    generalize
      (Rplus_le_compat_l (IZR (Int_part r1) + IZR (Int_part r2)) 0
                         (r1 + r2 + - (IZR (Int_part r1) + IZR (Int_part r2))) H1);
    intro; clear H1;
    generalize
      (Rplus_lt_compat_l (IZR (Int_part r1) + IZR (Int_part r2))
                         (r1 + r2 + - (IZR (Int_part r1) + IZR (Int_part r2))) 1 H);
    intro; clear H;
    rewrite (Rplus_comm (r1 + r2) (- (IZR (Int_part r1) + IZR (Int_part r2))))
    in H1;
    rewrite <-
            (Rplus_assoc (IZR (Int_part r1) + IZR (Int_part r2))
                         (- (IZR (Int_part r1) + IZR (Int_part r2))) (r1 + r2))
    in H1; rewrite (Rplus_opp_r (IZR (Int_part r1) + IZR (Int_part r2))) in H1;
    elim (Rplus_ne (r1 + r2)); intros a b; rewrite b in H1;
    clear a b;
    rewrite (Rplus_comm (r1 + r2) (- (IZR (Int_part r1) + IZR (Int_part r2))))
    in H0;
    rewrite <-
            (Rplus_assoc (IZR (Int_part r1) + IZR (Int_part r2))
                         (- (IZR (Int_part r1) + IZR (Int_part r2))) (r1 + r2))
    in H0; rewrite (Rplus_opp_r (IZR (Int_part r1) + IZR (Int_part r2))) in H0;
    elim (Rplus_ne (IZR (Int_part r1) + IZR (Int_part r2)));
    intros a b; rewrite a in H0; clear a b; elim (Rplus_ne (r1 + r2));
    intros a b; rewrite b in H0; clear a b.

rewrite <- (plus_IZR (Int_part r1) (Int_part r2)) in H0;
    rewrite <- (plus_IZR (Int_part r1) (Int_part r2)) in H1;
    rewrite <- (plus_IZR (Int_part r1 + Int_part r2) 1) in H1;
    generalize (up_tech (r1 + r2) (Int_part r1 + Int_part r2) H0 H1);
    intro; clear H0 H1; unfold Int_part at 1.

intros; unfold frac_part; generalize (plus_Int_part1 r1 r2 H); intro;
    rewrite H0; rewrite (plus_IZR (Int_part r1 + Int_part r2) 1);
    rewrite (plus_IZR (Int_part r1) (Int_part r2)); simpl;
    unfold Rminus at 3 4;
    rewrite (Rplus_assoc r1 (- IZR (Int_part r1)) (r2 + - IZR (Int_part r2)));
